from haystack import component

@component
class ClaimExtractor:
    @component.output_types(claims=list[str])
    def run(self, text: str):
        # Simple claim extraction logic
        claims = [s.strip() for s in text.split('.') if len(s) > 20]
        return {"claims": claims}

pipe = Pipeline()
pipe.add_component("extractor", ClaimExtractor())
pipe.add_component("generator", OpenAIGenerator())
pipe.connect("generator.text", "extractor.text")

def research_agent_loop(pipeline, query, max_iterations=3):
    context = []
    for i in range(max_iterations):
        result = pipeline.run({"query": query + f' (round {i+1})'})
        new_docs = result['retriever']['documents']
        if not new_docs: break
        context.extend(new_docs)
    return pipeline.run({"query": query, "documents": context})

