from haystack import component
from vex import VexClient

@component
class VexSourceVerifier:
    def __init__(self, vex_api_key: str):
        self.vex = VexClient(api_key=vex_api_key)

    @component.output_types(verified_docs=list, failed_docs=list)
    def run(self, documents: list):
        checks = [
            "source_verification",
            "recency_checks",
            "bias_detection"
        ]
        results = self.vex.verify({
            "input": [doc.content for doc in documents],
            "verifications": checks
        })
        verified = [doc for doc, res in zip(documents, results) if res.passed]
        return {
            "verified_docs": verified,
            "failed_docs": [doc for doc, res in zip(documents, results) if not res.passed]
        }
